"""
engine.py — Two-Level Inference Runtime & Phase Coherence Shield

Wraps the ONNX wave-math graph in an onnxruntime InferenceSession and
implements the two-level retrieval pipeline:

  Level 1 — Group scan   : wave interference over N_group centroids (fast)
  Level 2 — Chunk scan   : wave interference within winning groups only
  Coherence Shield       : hard threshold T_c at both levels
  Hebbian Phase Shift    : high-scoring chunks are nudged toward query phase
                           in real time, before the sleep cycle consolidates

The engine is a non-intrusive lens over the source database — it reads
candidate vectors through a SourceAdapter but never writes back.
"""

from __future__ import annotations

import math
from dataclasses import dataclass, field
from pathlib import Path
from typing import Dict, List, Optional, Tuple

import numpy as np

from .compiler import DEFAULT_OUTPUT, wavepack_encode, wavepack_encode_batch
from .frequency import FrequencyFamily
from .memory_map import ResonanceRegistry


# ─────────────────────────────────────────────────────────────────────────────
# Result type
# ─────────────────────────────────────────────────────────────────────────────

@dataclass(order=True)
class ResonanceResult:
    """A single retrieval hit with its interference score."""
    score: float
    chunk_id: str = field(compare=False)
    group_id: Optional[str] = field(default=None, compare=False)
    metadata: Dict = field(default_factory=dict, compare=False)


# ─────────────────────────────────────────────────────────────────────────────
# Engine
# ─────────────────────────────────────────────────────────────────────────────

class ResonanceEngine:
    """
    ONNX-backed wave-interference retrieval engine.

    Parameters
    ----------
    onnx_path           : Path to the compiled resonance_engine.onnx graph.
    registry            : Shared ResonanceRegistry (RAM sidecar).
    coherence_threshold : Hard score cutoff T_c (0–1 range typical).
                          Chunks below this are dropped before returning.
    top_k_groups        : How many groups to drill into at Level 1.
    hebbian_rate        : How strongly high-scoring chunks are phase-pulled
                          toward the query phase during inference (0 disables).
    hebbian_threshold   : Score percentile above which Hebbian update fires.
    providers           : ONNX execution providers in priority order.
    """

    def __init__(
        self,
        onnx_path: str | Path = DEFAULT_OUTPUT,
        registry: Optional[ResonanceRegistry] = None,
        coherence_threshold: float = 0.5,
        top_k_groups: int = 3,
        hebbian_rate: float = 0.02,
        hebbian_threshold: float = 0.75,
        providers: Optional[List[str]] = None,
    ) -> None:
        try:
            import onnxruntime as ort
        except ImportError as exc:
            raise ImportError(
                "onnxruntime is required: pip install onnxruntime"
            ) from exc

        self._registry  = registry or ResonanceRegistry()
        self.coherence_threshold = coherence_threshold
        self.top_k_groups = top_k_groups
        self.hebbian_rate = hebbian_rate
        self.hebbian_threshold = hebbian_threshold

        opts = ort.SessionOptions()
        opts.graph_optimization_level = ort.GraphOptimizationLevel.ORT_ENABLE_ALL
        opts.intra_op_num_threads = 4

        _providers = providers or ["CPUExecutionProvider"]
        self._session = ort.InferenceSession(
            str(onnx_path),
            sess_options=opts,
            providers=_providers,
        )

        # infer embedding dim N from the ONNX graph input shape
        input_shape = self._session.get_inputs()[0].shape
        self._flat_dim = input_shape[0] if input_shape[0] else None

    # ── Core inference ────────────────────────────────────────────────────

    def _run_onnx(
        self,
        query_wave: np.ndarray,    # (2N,)
        db_waves:   np.ndarray,    # (M, 2N)
    ) -> np.ndarray:               # (M,)
        """Execute one wave-interference pass through the ONNX graph."""
        scores = self._session.run(
            ["scores"],
            {
                "query":    query_wave.astype(np.float32),
                "db_batch": db_waves.astype(np.float32),
            },
        )[0]
        return scores

    def _encode_query(
        self,
        query_amplitude: np.ndarray,
        query_phase: float,
    ) -> np.ndarray:
        """Pack a query amplitude + phase into a 2N wavepacket."""
        return wavepack_encode(query_amplitude, query_phase)

    def _apply_hebbian_update(
        self,
        candidate_ids: List[str],
        scores: np.ndarray,
        query_phase: float,
    ) -> None:
        """
        Real-time phase shift: chunks that score above hebbian_threshold
        are nudged toward the query phase immediately during inference.

        This is a lightweight Hebbian update — the full synaptic alignment
        still happens during the sleep cycle, but this lets high-relevance
        chunks start drifting toward the query context right away.
        """
        if self.hebbian_rate <= 0:
            return

        threshold = float(np.quantile(scores, self.hebbian_threshold)) if len(scores) > 1 else self.coherence_threshold

        for i, cid in enumerate(candidate_ids):
            if scores[i] >= threshold:
                current_phi = self._registry.get_phi(cid)
                # Blend current phase toward query phase
                new_phi = (1.0 - self.hebbian_rate) * current_phi + self.hebbian_rate * query_phase
                self._registry.set_phi(cid, new_phi)

    # ── Two-level retrieval ───────────────────────────────────────────────

    def query_resonance(
        self,
        query_amplitude: np.ndarray,
        query_phase: float,
        candidate_ids: List[str],
        candidate_amplitudes: np.ndarray,        # (M, N) float32
        recency_boost: float = 0.05,
        co_activation_boost: float = 0.05,
    ) -> List[ResonanceResult]:
        """
        Full two-level resonance retrieval with real-time Hebbian phase shift.

        Level 1: scan group centroids, keep top_k_groups.
        Level 2: scan chunks within winning groups.
        Coherence Shield: drop chunks below coherence_threshold.
        Hebbian update: nudge high-scoring chunks toward query phase.
        """
        if len(candidate_ids) == 0:
            return []

        query_wave = self._encode_query(query_amplitude, query_phase)

        # ── Level 1: group scan ──────────────────────────────────────────
        winning_group_ids = self._group_scan(query_wave)

        # ── Level 2: chunk scan within winning groups ────────────────────
        if winning_group_ids:
            winning_set = set(winning_group_ids)
            filtered_ids = []
            filtered_amps = []
            for cid, amp in zip(candidate_ids, candidate_amplitudes):
                chunk_meta = self._registry._chunks.get(cid)
                if chunk_meta is None or chunk_meta.group_id in winning_set:
                    filtered_ids.append(cid)
                    filtered_amps.append(amp)
            if filtered_ids:
                candidate_ids = filtered_ids
                candidate_amplitudes = np.stack(filtered_amps, axis=0)

        # Retrieve phase angles from registry
        phis = self._registry.get_phis_batch(candidate_ids)

        # Encode all candidates into 2N wavepackets
        db_waves = wavepack_encode_batch(candidate_amplitudes, phis)

        # Run ONNX interference
        raw_scores = self._run_onnx(query_wave, db_waves)

        # ── Hebbian real-time phase shift ────────────────────────────────
        self._apply_hebbian_update(candidate_ids, raw_scores, query_phase)

        # ── Apply recency / co-activation boosts ─────────────────────────
        scores = raw_scores.copy()
        now    = __import__("time").time()

        for i, cid in enumerate(candidate_ids):
            chunk = self._registry._chunks.get(cid)
            if chunk is None:
                continue
            if recency_boost > 0:
                staleness = now - chunk.last_access
                scores[i] += recency_boost * math.exp(-staleness / 3600.0)
            if co_activation_boost > 0:
                total_coact = sum(
                    v for (a, b), v in self._registry._chunk_coact.items()
                    if a == cid or b == cid
                )
                if total_coact > 0:
                    scores[i] += co_activation_boost * min(1.0, total_coact / 50.0)

        # ── Coherence Shield ─────────────────────────────────────────────
        results = []
        for i, cid in enumerate(candidate_ids):
            if scores[i] >= self.coherence_threshold:
                chunk = self._registry._chunks.get(cid)
                results.append(ResonanceResult(
                    score=float(scores[i]),
                    chunk_id=cid,
                    group_id=chunk.group_id if chunk else None,
                ))
                self._registry.record_access(cid)

        results.sort(reverse=True)
        return results

    def _group_scan(self, query_wave: np.ndarray) -> List[str]:
        """
        Level 1: run wave interference over all group centroids.
        Returns IDs of the top_k_groups winning groups.
        """
        group_ids, group_matrix = self._registry.get_all_group_vectors()
        if not group_ids or group_matrix.shape[0] == 0:
            return []

        group_scores = self._run_onnx(query_wave, group_matrix)

        group_threshold = self.coherence_threshold * 0.5
        ranked = sorted(
            [(score, gid)
             for score, gid in zip(group_scores, group_ids)
             if score >= group_threshold],
            reverse=True,
        )
        return [gid for _, gid in ranked[:self.top_k_groups]]

    # ── Flat retrieval (bypass group scan — for small corpora) ────────────

    def query_flat(
        self,
        query_amplitude: np.ndarray,
        query_phase: float,
        candidate_ids: List[str],
        candidate_amplitudes: np.ndarray,
    ) -> List[ResonanceResult]:
        """
        Single-level scan over all candidates — no group pre-filter.
        Suitable for corpora smaller than ~500 chunks.
        Includes Hebbian real-time phase shift on high-scoring hits.
        """
        if len(candidate_ids) == 0:
            return []

        query_wave = self._encode_query(query_amplitude, query_phase)
        phis       = self._registry.get_phis_batch(candidate_ids)
        db_waves   = wavepack_encode_batch(candidate_amplitudes, phis)
        raw_scores = self._run_onnx(query_wave, db_waves)

        # Hebbian real-time phase shift
        self._apply_hebbian_update(candidate_ids, raw_scores, query_phase)

        results = []
        for i, cid in enumerate(candidate_ids):
            if raw_scores[i] >= self.coherence_threshold:
                chunk = self._registry._chunks.get(cid)
                results.append(ResonanceResult(
                    score=float(raw_scores[i]),
                    chunk_id=cid,
                    group_id=chunk.group_id if chunk else None,
                ))
                self._registry.record_access(cid)

        results.sort(reverse=True)
        return results

    @property
    def registry(self) -> ResonanceRegistry:
        return self._registry
